INSERT INTO `programs` (`id`, `slug`, `title`, `level`, `school`, `credential`, `summary`, `description`, `duration`, `study_mode`, `tuition`, `tuition_currency`, `image_url`, `icon`, `featured`, `published`, `sort_order`, `created_at`, `updated_at`) VALUES
(1, 'msc-global-leadership', 'MSc Global Leadership', 'Masters', 'School of Global Leadership', 'Master of Science', 'Equip yourself to lead organisations, churches and communities across cultures with integrity, vision and a global perspective.', 'The MSc Global Leadership prepares experienced professionals and ministry leaders to navigate complex, cross-cultural environments. Drawing on Christian principles of servant leadership, the programme blends strategic management, organisational behaviour, ethics and missional thinking. Students complete a capstone leadership project applied to their own context.', '2 years (part-time, online)', 'Online', 7200, 'GBP', '/img/generated/gdcu-program-leadership-park-v2.webp', 'public', 1, 1, 1, '2026-06-26 11:44:47', '2026-06-26 11:44:47'),
(2, 'ma-postcolonial-theology', 'MA Post-Colonial Theology', 'Masters', 'School of Global Theology', 'Master of Arts', 'Engage theology through the lens of diaspora, migration and the global majority church to serve a changing world.', 'This programme examines Scripture, tradition and contemporary theology from post-colonial and diaspora perspectives. Students explore migration, identity, justice and mission, equipping them to minister effectively within multicultural and diaspora communities.', '2 years (part-time, online)', 'Online', 6800, 'GBP', '/img/generated/gdcu-program-theology-living-room-v2.webp', 'menu_book', 1, 1, 2, '2026-06-26 11:44:47', '2026-06-26 11:44:47'),
(3, 'ba-theology-ministry', 'BA Theology & Ministry', 'Undergraduate', 'School of Global Theology', 'Bachelor of Arts', 'A foundational degree in biblical studies, theology and practical ministry for the next generation of Christian leaders.', 'The BA Theology & Ministry provides a thorough grounding in biblical languages, church history, systematic theology and pastoral practice. Designed for flexible online study, it equips students for ordained ministry, missions and lay leadership.', '3 years (online)', 'Online', 5400, 'GBP', '/img/generated/gdcu-student-video-lesson-home.webp', 'church', 0, 1, 3, '2026-06-26 11:44:47', '2026-06-26 11:44:47'),
(4, 'diploma-church-leadership', 'Diploma in Church Leadership', 'Diploma', 'School of Global Leadership', 'Undergraduate Diploma', 'Develop practical leadership skills to grow and shepherd a healthy, mission-focused local church.', 'This vocational diploma focuses on the practicalities of leading a local congregation — preaching, discipleship, governance, finance and pastoral care — within a sound theological framework.', '1 year (online)', 'Online', 2800, 'GBP', '/img/generated/gdcu-teacher-living-room-v2.webp', 'diversity_3', 0, 1, 4, '2026-06-26 11:44:47', '2026-06-26 11:44:47'),
(5, 'diploma-community-leadership', 'Diploma in Community Leadership', 'Diploma', 'School of Global Leadership', 'Undergraduate Diploma', 'Lead transformational change in diaspora and local communities through faith-driven service.', 'Equips community workers, charity leaders and volunteers with the skills to mobilise people, manage projects and create lasting social impact rooted in Christian values.', '1 year (online)', 'Online', 2800, 'GBP', '/img/generated/gdcu-student-courtyard-learning.webp', 'groups', 0, 1, 5, '2026-06-26 11:44:47', '2026-06-26 11:44:47'),
(6, 'msc-business-administration', 'MBA — Faith-Led Business', 'Masters', 'School of Business & Enterprise', 'Master of Business Administration', 'Lead enterprises with integrity, combining rigorous business strategy with a Christian ethic of stewardship.', 'A practical MBA for entrepreneurs and managers who want to build profitable, ethical organisations. Covers strategy, finance, marketing, operations and ethical leadership, with a focus on the diaspora economy.', '2 years (part-time, online)', 'Online', 7600, 'GBP', '/img/generated/gdcu-program-mba-home-v2.webp', 'business_center', 1, 1, 6, '2026-06-26 11:44:47', '2026-06-26 11:44:47'),
(7, 'certificate-diaspora-mission', 'Certificate in Diaspora Care & Mission', 'Certificate', 'School of Global Theology', 'Certificate of Higher Education', 'A short, accessible entry point into cross-cultural mission and pastoral care for diaspora communities.', 'This certificate introduces the theology and practice of diaspora mission — welcoming, discipling and serving migrant and refugee communities with compassion and cultural sensitivity.', '6 months (online)', 'Online', 1200, 'GBP', '/img/generated/gdcu-student-admissions-video.webp', 'volunteer_activism', 0, 1, 7, '2026-06-26 11:44:47', '2026-06-26 11:44:47'),
(8, 'phd-theology', 'PhD in Theology', 'Doctorate', 'School of Global Theology', 'Doctor of Philosophy', 'Undertake original, supervised research that contributes to global theological scholarship.', 'A research doctorate supervised by experienced faculty. Candidates produce an original thesis on a topic in theology, biblical studies or mission, contributing to the academy and the global church.', '4–6 years (online, by research)', 'Online', 4200, 'GBP', '/img/generated/gdcu-news-accreditation-park-v2.webp', 'school', 0, 1, 8, '2026-06-26 11:44:47', '2026-06-26 11:44:47');
INSERT INTO `courses` (`id`, `slug`, `program_id`, `instructor_id`, `code`, `title`, `summary`, `description`, `credits`, `icon`, `published`, `sort_order`, `created_at`, `updated_at`, `drip_feed_enabled`, `drip_feed_interval_hours`, `featured_image`) VALUES
(1, 'church-leadership-foundations', 4, NULL, 'LEAD101', 'Foundations of Church Leadership', 'Core principles of servant leadership for the local church.', 'This course lays the biblical and practical foundations for leading a healthy, mission-focused local church — covering servant leadership, vision, discipleship and governance.', 15, 'diversity_3', 1, 1, '2026-06-26 11:44:48', '2026-06-26 11:44:48', 0, 4, '/img/generated/gdcu-online-learning.webp'),
(2, 'biblical-hermeneutics', 3, NULL, 'THEO101', 'Biblical Hermeneutics II', 'Principles and practice of interpreting Scripture faithfully.', 'A study of the principles of biblical interpretation, equipping students to read, understand and apply Scripture responsibly across genres and contexts.', 15, 'menu_book', 1, 2, '2026-06-26 11:44:48', '2026-06-26 11:44:48', 0, 4, '/img/generated/gdcu-program-leadership-park-v2.webp'),
(3, 'ba-theology-ministry', 3, NULL, 'THEO1101', 'BA Theology & Ministry', 'The full BA — a three-year, Christ-centred degree in theology and ministry.', 'Year 1 lays the groundwork: biblical overview, hermeneutics basics, spiritual disciplines, church history survey, introduction to systematic theology, pastoral care foundations, academic writing for theology, world Christianity, ethics, and mission foundations.', 120, 'school', 1, 1, '2026-06-26 11:44:49', '2026-06-26 14:56:12', 1, 4, '/img/generated/gdcu-program-theology-living-room-v2.webp'),
(9, 'mba-faith-led-business', 6, NULL, 'MBA7101', 'MBA — Faith-Led Business', 'Lead enterprises with integrity, combining rigorous business strategy with a Christian ethic of stewardship.', 'A practical MBA for entrepreneurs and managers who want to build profitable, ethical organisations. Covers strategy, finance, marketing, operations and ethical leadership, with a focus on the diaspora economy. Each module integrates biblical wisdom with contemporary business best practice.', 180, 'business_center', 1, 1, '2026-06-27 01:27:46', '2026-06-27 01:27:46', 1, 4, NULL);
