INSERT INTO `lessons` (`id`, `module_id`, `title`, `type`, `content`, `video_url`, `duration_min`, `sort_order`, `image_url`, `block_no`, `block_title`) VALUES
(1, 1, 'What the Bible says about leadership', 'reading', '<p>Leadership in Scripture begins with character and calling, not position.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 20, 1, NULL, NULL, NULL),
(2, 1, 'Servant leadership models', 'reading', '<p>Jesus redefined greatness as service. We examine practical models of servant leadership.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 25, 2, NULL, NULL, NULL),
(3, 1, 'Live session: Leading from who you are', 'live', '<p>Join the live webinar to discuss leading from identity in Christ.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', 'https://example.com/live/lead101-m1', 60, 3, NULL, NULL, NULL),
(4, 2, 'Integrity and accountability', 'reading', '<p>Trust is the currency of leadership. We explore building cultures of integrity.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 20, 1, NULL, NULL, NULL),
(5, 2, 'Financial stewardship in ministry', 'reading', '<p>Faithful stewardship of resources protects the mission and the leader.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 20, 2, NULL, NULL, NULL),
(6, 3, 'Communicating across cultures', 'reading', '<p>Diaspora ministry requires cultural intelligence and humility.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 25, 1, NULL, NULL, NULL),
(7, 3, 'Case study: A multicultural church plant', 'reading', '<p>We analyse a real-world diaspora church plant and its leadership lessons.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 30, 2, NULL, NULL, NULL),
(8, 4, 'What is hermeneutics?', 'reading', '<p>Hermeneutics is the art and science of interpretation.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 20, 1, NULL, NULL, NULL),
(9, 4, 'Context is king', 'reading', '<p>Every text has a literary, historical and theological context.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 25, 2, NULL, NULL, NULL),
(10, 5, 'Reading narrative', 'reading', '<p>Biblical narrative teaches through story; we learn to read it well.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 25, 1, NULL, NULL, NULL),
(11, 5, 'Reading the epistles', 'reading', '<p>Letters demand attention to argument and audience.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 25, 2, NULL, NULL, NULL),
(12, 5, 'Divine sovereignty and human will', 'reading', '<p>A worked example interpreting a difficult theological theme.</p><p>This lesson combines a short reading with reflection questions. Work through the material at your own pace, then mark the lesson complete to track your progress.</p><h3>Key ideas</h3><ul><li>Ground every principle in Scripture and sound theology.</li><li>Apply learning to your own context and calling.</li><li>Engage your cohort in the discussion forum.</li></ul><blockquote>"Whatever you do, work at it with all your heart, as working for the Lord." — Colossians 3:23</blockquote>', NULL, 30, 3, NULL, NULL, NULL),
(46, 17, 'The Synoptic Gospels: Matthew, Mark & Luke', 'video', '<p>The Gospels present Jesus from four angles; Acts shows the Spirit-empowered church carrying his mission from Jerusalem to the ends of the earth.</p><p>This lesson — <strong>The Synoptic Gospels: Matthew, Mark & Luke</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Each Gospel has a distinct portrait and audience.</li><li>The cross and resurrection are the climax of the story.</li><li>Acts is the bridge from Jesus to the global church.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Mark%201%3A1-15&version=NIVUK" target="_blank" rel="noopener"><strong>Mark 1:1-15</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Synoptic Gospels: Matthew, Mark & Luke</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=Q0BrP8bqj0c', 25, 1, NULL, NULL, NULL),
(47, 17, 'The Gospel of John', 'reading', '<p>The Gospels present Jesus from four angles; Acts shows the Spirit-empowered church carrying his mission from Jerusalem to the ends of the earth.</p><p>This lesson — <strong>The Gospel of John</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Each Gospel has a distinct portrait and audience.</li><li>The cross and resurrection are the climax of the story.</li><li>Acts is the bridge from Jesus to the global church.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%202%3A1-21&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 2:1-21</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Gospel of John</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(48, 17, 'Acts: The Spirit-Empowered Church', 'reading', '<p>The Gospels present Jesus from four angles; Acts shows the Spirit-empowered church carrying his mission from Jerusalem to the ends of the earth.</p><p>This lesson — <strong>Acts: The Spirit-Empowered Church</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Each Gospel has a distinct portrait and audience.</li><li>The cross and resurrection are the climax of the story.</li><li>Acts is the bridge from Jesus to the global church.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Mark%201%3A1-15&version=NIVUK" target="_blank" rel="noopener"><strong>Mark 1:1-15</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Acts: The Spirit-Empowered Church</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(49, 18, 'Reading Apocalyptic Literature', 'video', '<p>Advanced interpretation engages biblical languages, literary structures, intertextuality and the history of interpretation to read Scripture with greater depth.</p><p>This lesson — <strong>Reading Apocalyptic Literature</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The biblical authors quote and echo earlier Scripture intentionally.</li><li>Word studies and structure reveal an author’s emphasis.</li><li>We read with the church across history, not alone.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Luke%2024%3A44-49&version=NIVUK" target="_blank" rel="noopener"><strong>Luke 24:44-49</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Reading Apocalyptic Literature</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=plSNIwhAn5o', 25, 1, NULL, NULL, NULL),
(50, 18, 'Reading Wisdom Literature', 'reading', '<p>Advanced interpretation engages biblical languages, literary structures, intertextuality and the history of interpretation to read Scripture with greater depth.</p><p>This lesson — <strong>Reading Wisdom Literature</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The biblical authors quote and echo earlier Scripture intentionally.</li><li>Word studies and structure reveal an author’s emphasis.</li><li>We read with the church across history, not alone.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Psalm%201&version=NIVUK" target="_blank" rel="noopener"><strong>Psalm 1</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Reading Wisdom Literature</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(51, 18, 'Post-Colonial & Diaspora Hermeneutics', 'reading', '<p>Advanced interpretation engages biblical languages, literary structures, intertextuality and the history of interpretation to read Scripture with greater depth.</p><p>This lesson — <strong>Post-Colonial & Diaspora Hermeneutics</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The biblical authors quote and echo earlier Scripture intentionally.</li><li>Word studies and structure reveal an author’s emphasis.</li><li>We read with the church across history, not alone.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Luke%2024%3A44-49&version=NIVUK" target="_blank" rel="noopener"><strong>Luke 24:44-49</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Post-Colonial & Diaspora Hermeneutics</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(52, 19, 'The Theology of Preaching', 'video', '<p>Homiletics is the craft of preaching: faithfully explaining a text and applying it to real lives so that the congregation hears the voice of God.</p><p>This lesson — <strong>The Theology of Preaching</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Good preaching is rooted in careful exegesis of one text.</li><li>Sermons move from text, to theme, to transformation.</li><li>Delivery, clarity and prayerful dependence all matter.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=2%20Timothy%204%3A1-5&version=NIVUK" target="_blank" rel="noopener"><strong>2 Timothy 4:1-5</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Theology of Preaching</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=7_CGP-12AE0', 25, 1, NULL, NULL, NULL),
(53, 19, 'From Text to Sermon', 'reading', '<p>Homiletics is the craft of preaching: faithfully explaining a text and applying it to real lives so that the congregation hears the voice of God.</p><p>This lesson — <strong>From Text to Sermon</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Good preaching is rooted in careful exegesis of one text.</li><li>Sermons move from text, to theme, to transformation.</li><li>Delivery, clarity and prayerful dependence all matter.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Nehemiah%208%3A8&version=NIVUK" target="_blank" rel="noopener"><strong>Nehemiah 8:8</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>From Text to Sermon</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(54, 19, 'Preaching in Different Contexts', 'reading', '<p>Homiletics is the craft of preaching: faithfully explaining a text and applying it to real lives so that the congregation hears the voice of God.</p><p>This lesson — <strong>Preaching in Different Contexts</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Good preaching is rooted in careful exegesis of one text.</li><li>Sermons move from text, to theme, to transformation.</li><li>Delivery, clarity and prayerful dependence all matter.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=2%20Timothy%204%3A1-5&version=NIVUK" target="_blank" rel="noopener"><strong>2 Timothy 4:1-5</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Preaching in Different Contexts</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(55, 20, 'A Biblical Theology of Worship', 'video', '<p>Worship is the church’s response to God’s glory. Liturgy gives shape and rhythm to that response across the week and the Christian year.</p><p>This lesson — <strong>A Biblical Theology of Worship</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Worship is for God yet forms the worshippers.</li><li>Word and table, song and prayer all carry the gospel.</li><li>Liturgical rhythm disciples us over time.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Psalm%2095&version=NIVUK" target="_blank" rel="noopener"><strong>Psalm 95</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>A Biblical Theology of Worship</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=f7RJATbobik', 25, 1, NULL, NULL, NULL),
(56, 20, 'Liturgical Traditions Across Cultures', 'reading', '<p>Worship is the church’s response to God’s glory. Liturgy gives shape and rhythm to that response across the week and the Christian year.</p><p>This lesson — <strong>Liturgical Traditions Across Cultures</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Worship is for God yet forms the worshippers.</li><li>Word and table, song and prayer all carry the gospel.</li><li>Liturgical rhythm disciples us over time.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=John%204%3A19-26&version=NIVUK" target="_blank" rel="noopener"><strong>John 4:19-26</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Liturgical Traditions Across Cultures</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(57, 20, 'Designing a Worship Service', 'reading', '<p>Worship is the church’s response to God’s glory. Liturgy gives shape and rhythm to that response across the week and the Christian year.</p><p>This lesson — <strong>Designing a Worship Service</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Worship is for God yet forms the worshippers.</li><li>Word and table, song and prayer all carry the gospel.</li><li>Liturgical rhythm disciples us over time.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Psalm%2095&version=NIVUK" target="_blank" rel="noopener"><strong>Psalm 95</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Designing a Worship Service</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(58, 21, 'Counselling Theory for Pastors', 'video', '<p>Pastoral counselling brings the comfort and wisdom of Christ to people in crisis, grief, conflict and decision, knowing when to walk alongside and when to refer.</p><p>This lesson — <strong>Counselling Theory for Pastors</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Listening well is the first act of care.</li><li>Scripture and prayer accompany, not replace, wise practice.</li><li>Know your limits and refer to professionals when needed.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=2%20Corinthians%201%3A3-7&version=NIVUK" target="_blank" rel="noopener"><strong>2 Corinthians 1:3-7</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Counselling Theory for Pastors</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=8Tbcofs6l3o', 25, 1, NULL, NULL, NULL),
(59, 21, 'Marriage & Family Counselling', 'reading', '<p>Pastoral counselling brings the comfort and wisdom of Christ to people in crisis, grief, conflict and decision, knowing when to walk alongside and when to refer.</p><p>This lesson — <strong>Marriage & Family Counselling</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Listening well is the first act of care.</li><li>Scripture and prayer accompany, not replace, wise practice.</li><li>Know your limits and refer to professionals when needed.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Proverbs%2015%3A1&version=NIVUK" target="_blank" rel="noopener"><strong>Proverbs 15:1</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Marriage & Family Counselling</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(60, 21, 'Trauma-Informed Pastoral Care', 'reading', '<p>Pastoral counselling brings the comfort and wisdom of Christ to people in crisis, grief, conflict and decision, knowing when to walk alongside and when to refer.</p><p>This lesson — <strong>Trauma-Informed Pastoral Care</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Listening well is the first act of care.</li><li>Scripture and prayer accompany, not replace, wise practice.</li><li>Know your limits and refer to professionals when needed.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=2%20Corinthians%201%3A3-7&version=NIVUK" target="_blank" rel="noopener"><strong>2 Corinthians 1:3-7</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Trauma-Informed Pastoral Care</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(61, 22, 'The Hypostatic Union', 'video', '<p>Christology and pneumatology explore the person and work of Christ and the Holy Spirit — the heart of Christian confession.</p><p>This lesson — <strong>The Hypostatic Union</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Jesus is fully God and fully human (Chalcedon).</li><li>His death and resurrection accomplish salvation.</li><li>The Spirit applies Christ’s work and empowers the church.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Philippians%202%3A5-11&version=NIVUK" target="_blank" rel="noopener"><strong>Philippians 2:5-11</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Hypostatic Union</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=GGCF3OPWN14', 25, 1, NULL, NULL, NULL),
(62, 22, 'The Holy Spirit in the Old & New Testaments', 'reading', '<p>Christology and pneumatology explore the person and work of Christ and the Holy Spirit — the heart of Christian confession.</p><p>This lesson — <strong>The Holy Spirit in the Old & New Testaments</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Jesus is fully God and fully human (Chalcedon).</li><li>His death and resurrection accomplish salvation.</li><li>The Spirit applies Christ’s work and empowers the church.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=John%2016%3A5-15&version=NIVUK" target="_blank" rel="noopener"><strong>John 16:5-15</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Holy Spirit in the Old & New Testaments</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(63, 22, 'Spiritual Gifts & the Charismatic Question', 'reading', '<p>Christology and pneumatology explore the person and work of Christ and the Holy Spirit — the heart of Christian confession.</p><p>This lesson — <strong>Spiritual Gifts & the Charismatic Question</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Jesus is fully God and fully human (Chalcedon).</li><li>His death and resurrection accomplish salvation.</li><li>The Spirit applies Christ’s work and empowers the church.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Philippians%202%3A5-11&version=NIVUK" target="_blank" rel="noopener"><strong>Philippians 2:5-11</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Spiritual Gifts & the Charismatic Question</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(64, 23, 'The Radical Reformation & Anabaptists', 'video', '<p>From the Reformation to the present, the church has been reshaped by renewal, revival, global mission and the challenges of the modern world.</p><p>This lesson — <strong>The Radical Reformation & Anabaptists</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The Reformation recovered grace, faith and Scripture.</li><li>Revivals and missionary movements spread the faith worldwide.</li><li>The modern church faces secularism, pluralism and rapid change.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Romans%201%3A16-17&version=NIVUK" target="_blank" rel="noopener"><strong>Romans 1:16-17</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Radical Reformation & Anabaptists</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=7_CGP-12AE0', 25, 1, NULL, NULL, NULL),
(65, 23, 'Revivalism & the Great Awakenings', 'reading', '<p>From the Reformation to the present, the church has been reshaped by renewal, revival, global mission and the challenges of the modern world.</p><p>This lesson — <strong>Revivalism & the Great Awakenings</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The Reformation recovered grace, faith and Scripture.</li><li>Revivals and missionary movements spread the faith worldwide.</li><li>The modern church faces secularism, pluralism and rapid change.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Ephesians%202%3A8-10&version=NIVUK" target="_blank" rel="noopener"><strong>Ephesians 2:8-10</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Revivalism & the Great Awakenings</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(66, 23, 'Pentecostalism & the Charismatic Movement', 'reading', '<p>From the Reformation to the present, the church has been reshaped by renewal, revival, global mission and the challenges of the modern world.</p><p>This lesson — <strong>Pentecostalism & the Charismatic Movement</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The Reformation recovered grace, faith and Scripture.</li><li>Revivals and missionary movements spread the faith worldwide.</li><li>The modern church faces secularism, pluralism and rapid change.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Romans%201%3A16-17&version=NIVUK" target="_blank" rel="noopener"><strong>Romans 1:16-17</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Pentecostalism & the Charismatic Movement</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(67, 24, 'Theology of Youth Ministry', 'video', '<p>Youth and family ministry disciples the next generation, partnering with parents and forming faith that lasts beyond adolescence.</p><p>This lesson — <strong>Theology of Youth Ministry</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Faith is best formed in the home and the worshipping community.</li><li>Young people need belonging before believing and behaving.</li><li>Ministry equips parents as the primary disciplers.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Deuteronomy%206%3A4-9&version=NIVUK" target="_blank" rel="noopener"><strong>Deuteronomy 6:4-9</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Theology of Youth Ministry</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=8Tbcofs6l3o', 25, 1, NULL, NULL, NULL),
(68, 24, 'Programmes, Mentoring & Discipleship', 'reading', '<p>Youth and family ministry disciples the next generation, partnering with parents and forming faith that lasts beyond adolescence.</p><p>This lesson — <strong>Programmes, Mentoring & Discipleship</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Faith is best formed in the home and the worshipping community.</li><li>Young people need belonging before believing and behaving.</li><li>Ministry equips parents as the primary disciplers.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=2%20Timothy%201%3A5&version=NIVUK" target="_blank" rel="noopener"><strong>2 Timothy 1:5</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Programmes, Mentoring & Discipleship</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(69, 24, 'Engaging Digital Natives', 'reading', '<p>Youth and family ministry disciples the next generation, partnering with parents and forming faith that lasts beyond adolescence.</p><p>This lesson — <strong>Engaging Digital Natives</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Faith is best formed in the home and the worshipping community.</li><li>Young people need belonging before believing and behaving.</li><li>Ministry equips parents as the primary disciplers.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Deuteronomy%206%3A4-9&version=NIVUK" target="_blank" rel="noopener"><strong>Deuteronomy 6:4-9</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Engaging Digital Natives</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(70, 25, 'Biblical Models of Church Governance', 'video', '<p>Healthy churches need wise administration: governance, finance, safeguarding and clear structures that serve the mission rather than smother it.</p><p>This lesson — <strong>Biblical Models of Church Governance</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Good governance protects people and enables ministry.</li><li>Stewardship of money and data is a gospel issue.</li><li>Systems exist to serve people, not the reverse.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%206%3A1-7&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 6:1-7</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Biblical Models of Church Governance</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=plSNIwhAn5o', 25, 1, NULL, NULL, NULL),
(71, 25, 'Strategic Planning for Ministry', 'reading', '<p>Healthy churches need wise administration: governance, finance, safeguarding and clear structures that serve the mission rather than smother it.</p><p>This lesson — <strong>Strategic Planning for Ministry</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Good governance protects people and enables ministry.</li><li>Stewardship of money and data is a gospel issue.</li><li>Systems exist to serve people, not the reverse.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=1%20Corinthians%2014%3A40&version=NIVUK" target="_blank" rel="noopener"><strong>1 Corinthians 14:40</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Strategic Planning for Ministry</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(72, 25, 'Year 2 Integration & Reflection', 'reading', '<p>Healthy churches need wise administration: governance, finance, safeguarding and clear structures that serve the mission rather than smother it.</p><p>This lesson — <strong>Year 2 Integration & Reflection</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Good governance protects people and enables ministry.</li><li>Stewardship of money and data is a gospel issue.</li><li>Systems exist to serve people, not the reverse.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%206%3A1-7&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 6:1-7</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Year 2 Integration & Reflection</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(73, 26, 'Paul\'s Life & Conversion', 'video', '<p>Paul’s letters work out the implications of the gospel for the church — justification, life in the Spirit, unity and hope.</p><p>This lesson — <strong>Paul\'s Life & Conversion</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Paul writes occasional letters into real church situations.</li><li>Justification by faith reframes Jew-Gentile unity.</li><li>Life in the Spirit produces a new community.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Romans%208%3A1-17&version=NIVUK" target="_blank" rel="noopener"><strong>Romans 8:1-17</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Paul\'s Life & Conversion</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=Q0BrP8bqj0c', 25, 1, NULL, NULL, NULL),
(74, 26, 'Romans: The Gospel Unveiled', 'reading', '<p>Paul’s letters work out the implications of the gospel for the church — justification, life in the Spirit, unity and hope.</p><p>This lesson — <strong>Romans: The Gospel Unveiled</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Paul writes occasional letters into real church situations.</li><li>Justification by faith reframes Jew-Gentile unity.</li><li>Life in the Spirit produces a new community.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Galatians%202%3A15-21&version=NIVUK" target="_blank" rel="noopener"><strong>Galatians 2:15-21</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Romans: The Gospel Unveiled</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(75, 26, 'The Prison Epistles', 'reading', '<p>Paul’s letters work out the implications of the gospel for the church — justification, life in the Spirit, unity and hope.</p><p>This lesson — <strong>The Prison Epistles</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Paul writes occasional letters into real church situations.</li><li>Justification by faith reframes Jew-Gentile unity.</li><li>Life in the Spirit produces a new community.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Romans%208%3A1-17&version=NIVUK" target="_blank" rel="noopener"><strong>Romans 8:1-17</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Prison Epistles</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(76, 27, 'Isaiah: The Fifth Gospel', 'video', '<p>The prophets call God’s people back to covenant faithfulness, confront injustice and announce both judgement and hope.</p><p>This lesson — <strong>Isaiah: The Fifth Gospel</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Prophets are covenant prosecutors, not just predictors.</li><li>Justice and mercy are central to prophetic faith.</li><li>Hope and the promise of restoration run through the prophets.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Isaiah%201%3A10-20&version=NIVUK" target="_blank" rel="noopener"><strong>Isaiah 1:10-20</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Isaiah: The Fifth Gospel</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=7_CGP-12AE0', 25, 1, NULL, NULL, NULL),
(77, 27, 'Jeremiah & the New Covenant', 'reading', '<p>The prophets call God’s people back to covenant faithfulness, confront injustice and announce both judgement and hope.</p><p>This lesson — <strong>Jeremiah & the New Covenant</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Prophets are covenant prosecutors, not just predictors.</li><li>Justice and mercy are central to prophetic faith.</li><li>Hope and the promise of restoration run through the prophets.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Amos%205%3A21-24&version=NIVUK" target="_blank" rel="noopener"><strong>Amos 5:21-24</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Jeremiah & the New Covenant</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(78, 27, 'The Minor Prophets: Major Messages', 'reading', '<p>The prophets call God’s people back to covenant faithfulness, confront injustice and announce both judgement and hope.</p><p>This lesson — <strong>The Minor Prophets: Major Messages</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Prophets are covenant prosecutors, not just predictors.</li><li>Justice and mercy are central to prophetic faith.</li><li>Hope and the promise of restoration run through the prophets.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Isaiah%201%3A10-20&version=NIVUK" target="_blank" rel="noopener"><strong>Isaiah 1:10-20</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Minor Prophets: Major Messages</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(79, 28, 'The Kingdom: Already but Not Yet', 'video', '<p>Eschatology and ecclesiology study the last things and the nature of the church — the people of God living between Christ’s resurrection and return.</p><p>This lesson — <strong>The Kingdom: Already but Not Yet</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>We live in the “already/not yet” of the kingdom.</li><li>The church is the body of Christ and a foretaste of the kingdom.</li><li>Christian hope is resurrection and new creation, not escape.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=1%20Corinthians%2015%3A20-28&version=NIVUK" target="_blank" rel="noopener"><strong>1 Corinthians 15:20-28</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Kingdom: Already but Not Yet</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=f7RJATbobik', 25, 1, NULL, NULL, NULL),
(80, 28, 'The Church: One, Holy, Catholic & Apostolic', 'reading', '<p>Eschatology and ecclesiology study the last things and the nature of the church — the people of God living between Christ’s resurrection and return.</p><p>This lesson — <strong>The Church: One, Holy, Catholic & Apostolic</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>We live in the “already/not yet” of the kingdom.</li><li>The church is the body of Christ and a foretaste of the kingdom.</li><li>Christian hope is resurrection and new creation, not escape.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Revelation%2021%3A1-5&version=NIVUK" target="_blank" rel="noopener"><strong>Revelation 21:1-5</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Church: One, Holy, Catholic & Apostolic</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(81, 28, 'Heaven, Hell & New Creation', 'reading', '<p>Eschatology and ecclesiology study the last things and the nature of the church — the people of God living between Christ’s resurrection and return.</p><p>This lesson — <strong>Heaven, Hell & New Creation</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>We live in the “already/not yet” of the kingdom.</li><li>The church is the body of Christ and a foretaste of the kingdom.</li><li>Christian hope is resurrection and new creation, not escape.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=1%20Corinthians%2015%3A20-28&version=NIVUK" target="_blank" rel="noopener"><strong>1 Corinthians 15:20-28</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Heaven, Hell & New Creation</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(82, 29, 'The Task of Apologetics', 'video', '<p>Apologetics gives reasons for Christian hope with gentleness and respect, engaging doubts about God, suffering, science and the resurrection.</p><p>This lesson — <strong>The Task of Apologetics</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Apologetics is for the church’s confidence and the seeker’s questions.</li><li>The resurrection is the historical centre of Christian claims.</li><li>Tone matters: gentleness and respect, not winning arguments.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=1%20Peter%203%3A13-16&version=NIVUK" target="_blank" rel="noopener"><strong>1 Peter 3:13-16</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Task of Apologetics</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=ak06MSETeo4', 25, 1, NULL, NULL, NULL),
(83, 29, 'Arguments for God\'s Existence', 'reading', '<p>Apologetics gives reasons for Christian hope with gentleness and respect, engaging doubts about God, suffering, science and the resurrection.</p><p>This lesson — <strong>Arguments for God\'s Existence</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Apologetics is for the church’s confidence and the seeker’s questions.</li><li>The resurrection is the historical centre of Christian claims.</li><li>Tone matters: gentleness and respect, not winning arguments.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%2017%3A16-34&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 17:16-34</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Arguments for God\'s Existence</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(84, 29, 'The Problem of Evil & Suffering', 'reading', '<p>Apologetics gives reasons for Christian hope with gentleness and respect, engaging doubts about God, suffering, science and the resurrection.</p><p>This lesson — <strong>The Problem of Evil & Suffering</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Apologetics is for the church’s confidence and the seeker’s questions.</li><li>The resurrection is the historical centre of Christian claims.</li><li>Tone matters: gentleness and respect, not winning arguments.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=1%20Peter%203%3A13-16&version=NIVUK" target="_blank" rel="noopener"><strong>1 Peter 3:13-16</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Problem of Evil & Suffering</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(85, 30, 'Migration in the Bible', 'video', '<p>Diaspora missiology studies how scattered peoples carry the gospel across cultures — a defining feature of GDCU’s calling.</p><p>This lesson — <strong>Migration in the Bible</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>God has often worked through scattered and displaced people.</li><li>The diaspora is both a mission field and a mission force.</li><li>Cross-cultural humility is essential to faithful witness.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%2011%3A19-26&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 11:19-26</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Migration in the Bible</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=f7RJATbobik', 25, 1, NULL, NULL, NULL),
(86, 30, 'Diaspora as Mission Strategy', 'reading', '<p>Diaspora missiology studies how scattered peoples carry the gospel across cultures — a defining feature of GDCU’s calling.</p><p>This lesson — <strong>Diaspora as Mission Strategy</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>God has often worked through scattered and displaced people.</li><li>The diaspora is both a mission field and a mission force.</li><li>Cross-cultural humility is essential to faithful witness.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Jeremiah%2029%3A4-7&version=NIVUK" target="_blank" rel="noopener"><strong>Jeremiah 29:4-7</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Diaspora as Mission Strategy</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(87, 30, 'Reverse Mission: From the Margins to the Centre', 'reading', '<p>Diaspora missiology studies how scattered peoples carry the gospel across cultures — a defining feature of GDCU’s calling.</p><p>This lesson — <strong>Reverse Mission: From the Margins to the Centre</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>God has often worked through scattered and displaced people.</li><li>The diaspora is both a mission field and a mission force.</li><li>Cross-cultural humility is essential to faithful witness.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%2011%3A19-26&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 11:19-26</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Reverse Mission: From the Margins to the Centre</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(88, 31, 'Servant Leadership Revisited', 'video', '<p>Christian leadership is servant leadership — forming character, casting vision and developing others for the sake of the mission.</p><p>This lesson — <strong>Servant Leadership Revisited</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Leadership in the kingdom is cruciform service.</li><li>Leaders steward people, vision and resources.</li><li>Healthy leaders develop other leaders.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Mark%2010%3A42-45&version=NIVUK" target="_blank" rel="noopener"><strong>Mark 10:42-45</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Servant Leadership Revisited</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=8Tbcofs6l3o', 25, 1, NULL, NULL, NULL),
(89, 31, 'Leading Through Change & Conflict', 'reading', '<p>Christian leadership is servant leadership — forming character, casting vision and developing others for the sake of the mission.</p><p>This lesson — <strong>Leading Through Change & Conflict</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Leadership in the kingdom is cruciform service.</li><li>Leaders steward people, vision and resources.</li><li>Healthy leaders develop other leaders.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Nehemiah%202%3A11-18&version=NIVUK" target="_blank" rel="noopener"><strong>Nehemiah 2:11-18</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Leading Through Change & Conflict</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(90, 31, 'Developing Teams & Succession', 'reading', '<p>Christian leadership is servant leadership — forming character, casting vision and developing others for the sake of the mission.</p><p>This lesson — <strong>Developing Teams & Succession</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Leadership in the kingdom is cruciform service.</li><li>Leaders steward people, vision and resources.</li><li>Healthy leaders develop other leaders.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Mark%2010%3A42-45&version=NIVUK" target="_blank" rel="noopener"><strong>Mark 10:42-45</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Developing Teams & Succession</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(91, 32, 'New Testament Models of Church Planting', 'video', '<p>Church planting and fresh expressions reach new people and places with contextual, reproducing communities of faith.</p><p>This lesson — <strong>New Testament Models of Church Planting</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Planting follows the missionary pattern of Acts.</li><li>Context shapes the form a church takes.</li><li>Reproducing disciples and leaders is the goal.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%2014%3A21-23&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 14:21-23</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>New Testament Models of Church Planting</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=f7RJATbobik', 25, 1, NULL, NULL, NULL),
(92, 32, 'Fresh Expressions & Pioneering', 'reading', '<p>Church planting and fresh expressions reach new people and places with contextual, reproducing communities of faith.</p><p>This lesson — <strong>Fresh Expressions & Pioneering</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Planting follows the missionary pattern of Acts.</li><li>Context shapes the form a church takes.</li><li>Reproducing disciples and leaders is the goal.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=1%20Corinthians%203%3A5-9&version=NIVUK" target="_blank" rel="noopener"><strong>1 Corinthians 3:5-9</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Fresh Expressions & Pioneering</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(93, 32, 'Developing a Church Plant Proposal', 'reading', '<p>Church planting and fresh expressions reach new people and places with contextual, reproducing communities of faith.</p><p>This lesson — <strong>Developing a Church Plant Proposal</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Planting follows the missionary pattern of Acts.</li><li>Context shapes the form a church takes.</li><li>Reproducing disciples and leaders is the goal.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%2014%3A21-23&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 14:21-23</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Developing a Church Plant Proposal</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(94, 33, 'The Biblical Basis for Justice', 'video', '<p>Public theology and social justice work out the gospel’s implications for poverty, power and the common good in the public square.</p><p>This lesson — <strong>The Biblical Basis for Justice</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The prophets and Jesus centre the poor and the oppressed.</li><li>Justice is rooted in the character of God.</li><li>The church engages society with both word and deed.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Luke%204%3A16-21&version=NIVUK" target="_blank" rel="noopener"><strong>Luke 4:16-21</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Biblical Basis for Justice</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=f7RJATbobik', 25, 1, NULL, NULL, NULL),
(95, 33, 'Racial Justice & Reconciliation', 'reading', '<p>Public theology and social justice work out the gospel’s implications for poverty, power and the common good in the public square.</p><p>This lesson — <strong>Racial Justice & Reconciliation</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The prophets and Jesus centre the poor and the oppressed.</li><li>Justice is rooted in the character of God.</li><li>The church engages society with both word and deed.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Isaiah%2058%3A6-12&version=NIVUK" target="_blank" rel="noopener"><strong>Isaiah 58:6-12</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Racial Justice & Reconciliation</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(96, 33, 'The Church & Public Policy', 'reading', '<p>Public theology and social justice work out the gospel’s implications for poverty, power and the common good in the public square.</p><p>This lesson — <strong>The Church & Public Policy</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>The prophets and Jesus centre the poor and the oppressed.</li><li>Justice is rooted in the character of God.</li><li>The church engages society with both word and deed.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Luke%204%3A16-21&version=NIVUK" target="_blank" rel="noopener"><strong>Luke 4:16-21</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>The Church & Public Policy</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(97, 34, 'A Theology of Religions', 'video', '<p>Interfaith engagement equips Christians to witness and live faithfully among neighbours of other faiths with conviction, humility and love.</p><p>This lesson — <strong>A Theology of Religions</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Clarity about the gospel and respect for neighbours go together.</li><li>Listening and friendship open doors for witness.</li><li>We hold conviction and charity without compromise.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%2017%3A22-31&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 17:22-31</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>A Theology of Religions</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=plSNIwhAn5o', 25, 1, NULL, NULL, NULL),
(98, 34, 'Understanding Islam', 'reading', '<p>Interfaith engagement equips Christians to witness and live faithfully among neighbours of other faiths with conviction, humility and love.</p><p>This lesson — <strong>Understanding Islam</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Clarity about the gospel and respect for neighbours go together.</li><li>Listening and friendship open doors for witness.</li><li>We hold conviction and charity without compromise.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Colossians%204%3A5-6&version=NIVUK" target="_blank" rel="noopener"><strong>Colossians 4:5-6</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Understanding Islam</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(99, 34, 'Engaging African Traditional Religion', 'reading', '<p>Interfaith engagement equips Christians to witness and live faithfully among neighbours of other faiths with conviction, humility and love.</p><p>This lesson — <strong>Engaging African Traditional Religion</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Clarity about the gospel and respect for neighbours go together.</li><li>Listening and friendship open doors for witness.</li><li>We hold conviction and charity without compromise.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Acts%2017%3A22-31&version=NIVUK" target="_blank" rel="noopener"><strong>Acts 17:22-31</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Engaging African Traditional Religion</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(100, 35, 'Research Methods for Ministry', 'video', '<p>The capstone integrates the whole degree into a supervised ministry project — research, theological reflection and practice brought together.</p><p>This lesson — <strong>Research Methods for Ministry</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Integration: bring together Bible, theology and practice.</li><li>Theological reflection turns experience into learning.</li><li>The project serves a real ministry context.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Colossians%203%3A23-24&version=NIVUK" target="_blank" rel="noopener"><strong>Colossians 3:23-24</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Research Methods for Ministry</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', 'https://www.youtube.com/watch?v=7_CGP-12AE0', 25, 1, NULL, NULL, NULL),
(101, 35, 'Project Design & Proposal Writing', 'reading', '<p>The capstone integrates the whole degree into a supervised ministry project — research, theological reflection and practice brought together.</p><p>This lesson — <strong>Project Design & Proposal Writing</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Integration: bring together Bible, theology and practice.</li><li>Theological reflection turns experience into learning.</li><li>The project serves a real ministry context.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=James%201%3A22-25&version=NIVUK" target="_blank" rel="noopener"><strong>James 1:22-25</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Project Design & Proposal Writing</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 2, NULL, NULL, NULL),
(102, 35, 'Graduation & Launch: From Student to Minister', 'reading', '<p>The capstone integrates the whole degree into a supervised ministry project — research, theological reflection and practice brought together.</p><p>This lesson — <strong>Graduation & Launch: From Student to Minister</strong> — builds on that foundation and prepares you for discussion with your cohort. Work through it prayerfully and take notes as you go.</p><h3>Key ideas</h3><ul><li>Integration: bring together Bible, theology and practice.</li><li>Theological reflection turns experience into learning.</li><li>The project serves a real ministry context.</li></ul><h3>Scripture focus</h3><p>Read <a href="https://www.biblegateway.com/passage/?search=Colossians%203%3A23-24&version=NIVUK" target="_blank" rel="noopener"><strong>Colossians 3:23-24</strong></a> slowly. What does this passage reveal about God and his purposes?</p><h3>Reflect &amp; discuss</h3><p>How does <em>Graduation & Launch: From Student to Minister</em> shape the way you will think, worship or serve this week? Post one insight and one question in the discussion forum.</p>', NULL, 20, 3, NULL, NULL, NULL),
(1063, 8, 'Read: Why Interpretation Matters', 'reading', '<p style="color:#6b6b60"><em>Estimated reading time: 7–10 minutes.</em></p>\n<h3>Why this matters</h3>\n<p>Hermeneutics is the discipline of interpreting Scripture well — reading each text according to its genre, context and place in the biblical story.</p>\n<p>In this lesson we focus on <strong>Why Interpretation Matters</strong>, one of the foundational topics within biblical interpretation. Getting it right shapes how you read Scripture, how you pray and worship, and how you serve and lead others. Read this slowly — perhaps twice — with a Bible and a notebook beside you. The goal is not simply to gather information for an assignment, but to let the truth take root and change you. As the apostle Paul writes, we are transformed by the renewing of our minds, and that renewal begins with careful, prayerful attention.</p>\n<p>Before you read on, pause for a moment of prayer. Ask God to open your understanding and to make this lesson more than an academic exercise. The best theology is always done on our knees as well as at our desks.</p>\n<h3>Getting our bearings</h3>\n<p>Whenever we approach a topic like <strong>Why Interpretation Matters</strong>, it helps to slow down and ask what we actually mean by the words we are using. Christians sometimes assume everyone shares the same definitions, and a great deal of confusion comes from skipping this step. So take a moment to write down, in your own words, what you already think about why interpretation matters. Where did that understanding come from — a sermon, a book, your family, your culture? Naming our starting point honestly is the first act of good learning, because it lets us hold our assumptions up to the light of Scripture rather than reading our assumptions into Scripture.</p>\n<p>You will notice that the Bible rarely hands us a tidy, dictionary-style definition. Instead it tells a story and invites us to live inside it. Why Interpretation Matters is therefore best understood not as an abstract idea to be filed away, but as a thread woven through the whole drama of Scripture — a drama that finds its centre and fulfilment in Jesus Christ.</p>\n<h3>What Scripture says</h3>\n<p>Begin with the Bible itself. Read <a href="https://www.biblegateway.com/passage/?search=2%20Timothy%202%3A15&version=NIVUK" target="_blank" rel="noopener"><strong>2 Timothy 2:15</strong></a> before going further; do not rush past it. Scripture is our first and final authority, and every Christian conviction about why interpretation matters must be tested against it rather than against our preferences or traditions.</p>\n<p>As you read, ask three questions. First, what did this text mean for its original hearers, in their language, culture and moment? Second, how does it fit within the Bible’s one unfolding story of creation, fall, redemption and new creation? Third, what does it reveal about the character and purposes of God? These three questions — the historical, the canonical and the theological — keep us from twisting a verse to say whatever we want. Write down at least one observation under each question before moving on.</p>\n<h3>Across the Bible’s story</h3>\n<p>No single passage stands alone. Why Interpretation Matters appears, in different forms, from the opening chapters of Genesis through to the closing vision of Revelation. The same God who acts at creation is at work through Israel, supremely in Jesus, and now through his church by the Spirit. Tracing a theme across these movements guards us against building a whole doctrine on one isolated text, and it lets the clearer parts of Scripture illuminate the harder ones. As you study this year, keep asking: where else does the Bible touch on this, and how does the story as a whole shape what I am reading here?</p>\n<h3>How the church has understood it</h3>\n<p>Christians have reflected on why interpretation matters for two thousand years, and we are wise to learn from them rather than starting from scratch. The early church, the great councils, the Reformers, and theologians of the modern and global church have all wrestled with these questions and left us hard-won wisdom. Tradition is not a second authority standing above Scripture; it is a trustworthy companion — a long conversation of faithful readers that helps us avoid old errors and see what we might miss on our own.</p>\n<p>Where sincere Christians have disagreed, make it your habit to understand the strongest form of each view before you settle your own. Charity and humility are not weaknesses in a theologian; they are marks of maturity, and they protect both truth and unity.</p>\n<h3>A common misunderstanding</h3>\n<p>It is worth naming a frequent mistake here. Many people reduce why interpretation matters either to dry information that makes no difference to daily life, or to a private feeling disconnected from the teaching of Scripture. Both extremes fail. Genuine Christian understanding joins head and heart: it is rooted in the text, confessed with the church, and lived out in love. If your study of Why Interpretation Matters leaves you more proud, more anxious, or more detached from people, something has gone wrong in the method, however correct the conclusions.</p>\n<h3>In the global and diaspora church</h3>\n<p>GDCU exists for a worldwide, diaspora community, so we always ask how a topic lands across cultures. Why Interpretation Matters is often understood more richly when read through the eyes of the global church in Africa, Asia, Latin America and among scattered and migrant peoples. Your own context is not a problem to overcome but a gift that helps the whole body of Christ see more of the truth. As you read, consider how this topic speaks into your own community, its questions, its sufferings and its hopes.</p>\n<h3>For your life and ministry</h3>\n<p>Theology is meant to be lived. Ask yourself honestly: how should <strong>Why Interpretation Matters</strong> change the way I pray this week, the way I treat the people around me, and the way I lead or serve in my church and community? Choose one concrete, specific response — not a vague intention — and write it down. Good learning ends in worship and obedience, not merely in notes; the test of this lesson is not the quiz but your life.</p>\n<h3>Summary</h3>\n<ul>\n<li>Why Interpretation Matters is rooted in Scripture and must be tested against the whole biblical story, not one isolated verse.</li>\n<li>We read it with the historic and global church, holding conviction together with humility and charity.</li>\n<li>True understanding joins head and heart — text, confession and love.</li>\n<li>The aim is transformation: worship, character and faithful service, not information alone.</li>\n</ul>\n<h3>Reflect</h3>\n<p>Write two or three sentences explaining Why Interpretation Matters in your own words, as if to a friend who is new to faith. Then note one question you still have. Bring both to the supporting study, the video, and your cohort discussion.</p>', NULL, 9, 1, NULL, 1, 'Why Interpretation Matters'),
(1064, 8, 'Study: Why Interpretation Matters', 'reading', '<p style="color:#6b6b60"><em>Estimated reading time: 5–7 minutes.</em></p>\n<h3>A closer look: Why Interpretation Matters</h3>\n<p>The main reading gave you the big picture. This shorter reading helps you dig into the Bible for yourself, because the most important skill you can develop is reading Scripture well and prayerfully.</p>\n<h3>Study these passages</h3>\n<ol>\n<li>Read <a href="https://www.biblegateway.com/passage/?search=2%20Timothy%202%3A15&version=NIVUK" target="_blank" rel="noopener"><strong>2 Timothy 2:15</strong></a>. What does this passage show about why interpretation matters? Note one phrase that stands out.</li>\n<li>Read <a href="https://www.biblegateway.com/passage/?search=Nehemiah%208%3A1-8&version=NIVUK" target="_blank" rel="noopener"><strong>Nehemiah 8:1-8</strong></a>. How does it deepen or balance the first passage?</li>\n</ol>\n<h3>Questions for reflection &amp; discussion</h3>\n<ol>\n<li>In one sentence, how would you explain <strong>Why Interpretation Matters</strong> to someone in your church?</li>\n<li>Where do you see this lived out — well or poorly — in the world around you?</li>\n<li>What might God be inviting you to change in response?</li>\n<li>What question would you like to raise with your cohort?</li>\n</ol>\n<h3>Going further</h3>\n<ul>\n<li>Re-read both passages in a second translation and compare.</li>\n<li>Post your one-sentence explanation and your question in the discussion forum.</li>\n<li>Watch the video in the next lesson, then return and refine your answer.</li>\n</ul>', NULL, 6, 2, NULL, 1, 'Why Interpretation Matters'),
(1065, 8, 'Watch: Why Interpretation Matters', 'video', '<p>Now watch this <strong>~15&nbsp;minute</strong> teaching segment on <strong>Why Interpretation Matters</strong>. Have your notes from the two readings beside you.</p>\n<p>As you watch, listen for: (1) anything that confirms what you read, (2) anything new, and (3) one question it raises. Add these to your lesson notes, then mark the lesson complete.</p>', 'https://www.youtube.com/watch?v=GK2PBAG3064&start=0&end=900', 15, 3, NULL, 1, 'Why Interpretation Matters'),
(1066, 8, 'Read: The Goal of Interpretation', 'reading', '<p style="color:#6b6b60"><em>Estimated reading time: 7–10 minutes.</em></p>\n<h3>Why this matters</h3>\n<p>Hermeneutics is the discipline of interpreting Scripture well — reading each text according to its genre, context and place in the biblical story.</p>\n<p>In this lesson we focus on <strong>The Goal of Interpretation</strong>, one of the foundational topics within biblical interpretation. Getting it right shapes how you read Scripture, how you pray and worship, and how you serve and lead others. Read this slowly — perhaps twice — with a Bible and a notebook beside you. The goal is not simply to gather information for an assignment, but to let the truth take root and change you. As the apostle Paul writes, we are transformed by the renewing of our minds, and that renewal begins with careful, prayerful attention.</p>\n<p>Before you read on, pause for a moment of prayer. Ask God to open your understanding and to make this lesson more than an academic exercise. The best theology is always done on our knees as well as at our desks.</p>\n<h3>Getting our bearings</h3>\n<p>Whenever we approach a topic like <strong>The Goal of Interpretation</strong>, it helps to slow down and ask what we actually mean by the words we are using. Christians sometimes assume everyone shares the same definitions, and a great deal of confusion comes from skipping this step. So take a moment to write down, in your own words, what you already think about the goal of interpretation. Where did that understanding come from — a sermon, a book, your family, your culture? Naming our starting point honestly is the first act of good learning, because it lets us hold our assumptions up to the light of Scripture rather than reading our assumptions into Scripture.</p>\n<p>You will notice that the Bible rarely hands us a tidy, dictionary-style definition. Instead it tells a story and invites us to live inside it. The Goal of Interpretation is therefore best understood not as an abstract idea to be filed away, but as a thread woven through the whole drama of Scripture — a drama that finds its centre and fulfilment in Jesus Christ.</p>\n<h3>What Scripture says</h3>\n<p>Begin with the Bible itself. Read <a href="https://www.biblegateway.com/passage/?search=Nehemiah%208%3A1-8&version=NIVUK" target="_blank" rel="noopener"><strong>Nehemiah 8:1-8</strong></a> before going further; do not rush past it. Scripture is our first and final authority, and every Christian conviction about the goal of interpretation must be tested against it rather than against our preferences or traditions.</p>\n<p>As you read, ask three questions. First, what did this text mean for its original hearers, in their language, culture and moment? Second, how does it fit within the Bible’s one unfolding story of creation, fall, redemption and new creation? Third, what does it reveal about the character and purposes of God? These three questions — the historical, the canonical and the theological — keep us from twisting a verse to say whatever we want. Write down at least one observation under each question before moving on.</p>\n<h3>Across the Bible’s story</h3>\n<p>No single passage stands alone. The Goal of Interpretation appears, in different forms, from the opening chapters of Genesis through to the closing vision of Revelation. The same God who acts at creation is at work through Israel, supremely in Jesus, and now through his church by the Spirit. Tracing a theme across these movements guards us against building a whole doctrine on one isolated text, and it lets the clearer parts of Scripture illuminate the harder ones. As you study this year, keep asking: where else does the Bible touch on this, and how does the story as a whole shape what I am reading here?</p>\n<h3>How the church has understood it</h3>\n<p>Christians have reflected on the goal of interpretation for two thousand years, and we are wise to learn from them rather than starting from scratch. The early church, the great councils, the Reformers, and theologians of the modern and global church have all wrestled with these questions and left us hard-won wisdom. Tradition is not a second authority standing above Scripture; it is a trustworthy companion — a long conversation of faithful readers that helps us avoid old errors and see what we might miss on our own.</p>\n<p>Where sincere Christians have disagreed, make it your habit to understand the strongest form of each view before you settle your own. Charity and humility are not weaknesses in a theologian; they are marks of maturity, and they protect both truth and unity.</p>\n<h3>A common misunderstanding</h3>\n<p>It is worth naming a frequent mistake here. Many people reduce the goal of interpretation either to dry information that makes no difference to daily life, or to a private feeling disconnected from the teaching of Scripture. Both extremes fail. Genuine Christian understanding joins head and heart: it is rooted in the text, confessed with the church, and lived out in love. If your study of The Goal of Interpretation leaves you more proud, more anxious, or more detached from people, something has gone wrong in the method, however correct the conclusions.</p>\n<h3>In the global and diaspora church</h3>\n<p>GDCU exists for a worldwide, diaspora community, so we always ask how a topic lands across cultures. The Goal of Interpretation is often understood more richly when read through the eyes of the global church in Africa, Asia, Latin America and among scattered and migrant peoples. Your own context is not a problem to overcome but a gift that helps the whole body of Christ see more of the truth. As you read, consider how this topic speaks into your own community, its questions, its sufferings and its hopes.</p>\n<h3>For your life and ministry</h3>\n<p>Theology is meant to be lived. Ask yourself honestly: how should <strong>The Goal of Interpretation</strong> change the way I pray this week, the way I treat the people around me, and the way I lead or serve in my church and community? Choose one concrete, specific response — not a vague intention — and write it down. Good learning ends in worship and obedience, not merely in notes; the test of this lesson is not the quiz but your life.</p>\n<h3>Summary</h3>\n<ul>\n<li>The Goal of Interpretation is rooted in Scripture and must be tested against the whole biblical story, not one isolated verse.</li>\n<li>We read it with the historic and global church, holding conviction together with humility and charity.</li>\n<li>True understanding joins head and heart — text, confession and love.</li>\n<li>The aim is transformation: worship, character and faithful service, not information alone.</li>\n</ul>\n<h3>Reflect</h3>\n<p>Write two or three sentences explaining The Goal of Interpretation in your own words, as if to a friend who is new to faith. Then note one question you still have. Bring both to the supporting study, the video, and your cohort discussion.</p>', NULL, 9, 11, NULL, 2, 'The Goal of Interpretation'),
