INSERT INTO `quiz_questions` (`id`, `quiz_id`, `prompt`, `type`, `explanation`, `sort_order`) VALUES
(294, 89, 'The concept of "faithful stewardship" in business means…', 'single', 'Faithful stewardship means managing all resources — financial, human and environmental — in a manner that honours God and serves others.', 0),
(295, 89, 'According to Scripture, business and commerce are…', 'single', 'Genesis 1-2 establishes work, creativity and stewardship as part of God\'s good creation order.', 0),
(296, 89, 'The "diaspora advantage" in business refers to…', 'single', 'Diaspora entrepreneurs bring cross-cultural insight, transnational networks and a heart for both their heritage and adopted communities.', 0),
(297, 89, 'A faith-led business should pursue profit and purpose simultaneously.', 'truefalse', 'Profit and purpose are not opposed. A well-run business generates sustainable profit while serving the common good.', 0),
(298, 90, 'A company\'s mission statement should answer which question?', 'single', 'A mission statement defines the organisation\'s core purpose and reason for existing.', 0),
(299, 90, 'Blue Ocean Strategy emphasises…', 'single', 'Blue Ocean Strategy advocates creating uncontested market space rather than fighting over saturated markets.', 0),
(300, 90, 'According to Kotter, the first step in leading change is…', 'single', 'Kotter\'s first step is establishing urgency — helping people see the need for change.', 0),
(301, 90, 'A faith-led organisational culture can only be built with a 100% Christian workforce.', 'truefalse', 'Christian values can be embodied and modelled in any workplace, and diverse teams can thrive under shared ethical principles.', 0),
(302, 91, 'The accounting equation is…', 'single', 'Assets = Liabilities + Equity is the fundamental accounting equation that underpins the balance sheet.', 0),
(303, 91, 'A budget is best described as…', 'single', 'Budgets reveal what an organisation truly values and prioritises — making them moral and spiritual documents, not just financial ones.', 0),
(304, 91, 'Impact investing seeks to generate…', 'single', 'Impact investing aims to generate both financial return and measurable social/environmental benefit.', 0),
(305, 91, 'A cash flow statement is the same as a profit and loss statement.', 'truefalse', 'Cash flow and profit are different metrics. A company can be profitable but have negative cash flow, or vice versa.', 0),
(306, 92, 'Ethical marketing is primarily about…', 'single', 'Ethical marketing centres on truthfulness, customer well-being and building trust — not just maximising sales.', 0),
(307, 92, 'Data privacy in digital marketing should be guided by…', 'single', 'The Golden Rule — treating others as we would want to be treated — is a robust ethical framework for data privacy.', 0),
(308, 92, 'Customer complaints should be viewed as…', 'single', 'Complaints are opportunities to demonstrate humility, empathy and a commitment to excellence.', 0),
(309, 93, 'A B Corporation (B Corp) certification indicates that a company…', 'single', 'B Corp certification measures a company\'s social and environmental impact, accountability and transparency.', 0),
(310, 93, 'The "lean startup" methodology emphasises…', 'single', 'The lean startup approach prioritises quick experimentation, customer feedback and iterative product development.', 0),
(311, 93, 'Faith-led entrepreneurs should view competition as…', 'single', 'Healthy competition drives innovation and better service. Christians can compete with excellence and integrity simultaneously.', 0),
(312, 93, 'Ethical supply chain management includes ensuring fair wages and safe conditions for workers.', 'truefalse', 'Faith-led businesses must care about the people throughout their supply chain, not just direct employees.', 0),
(313, 94, 'The Triple Bottom Line measures success across which three dimensions?', 'single', 'The Triple Bottom Line (3Ps) evaluates an organisation\'s social, environmental and financial performance.', 0),
(314, 94, 'A non-executive director\'s primary role is to…', 'single', 'Non-executive directors bring independent judgement and oversight to board governance.', 0),
(315, 94, 'Virtue ethics asks which question when facing a dilemma?', 'single', 'Virtue ethics focuses on the character of the decision-maker rather than rules or consequences alone.', 0),
(316, 94, 'The goal of this MBA programme is to create Christian business leaders who separate their faith from their professional decisions.', 'truefalse', 'The programme\'s goal is the opposite — to integrate faith and business so that every decision reflects a Christian worldview.', 0),
(317, 95, 'Reflect on what you learned in Lessons 1–5 of Module 1 — Introduction to the Bible. What key principle stood out to you?', 'single', 'Review the lesson material and discussion forum for deeper insight.', 0),
(318, 96, 'Reflect on what you learned in Lessons 6–10 of Module 1 — Introduction to the Bible. What key principle stood out to you?', 'single', 'Review the lesson material and discussion forum for deeper insight.', 0),
(319, 97, 'Reflect on what you learned in Lessons 1–5 of Module 2 — Spiritual Formation & Discipleship. What key principle stood out to you?', 'single', 'Review the lesson material and discussion forum for deeper insight.', 0),
(320, 98, 'Reflect on what you learned in Lessons 6–10 of Module 2 — Spiritual Formation & Discipleship. What key principle stood out to you?', 'single', 'Review the lesson material and discussion forum for deeper insight.', 0);
